// ============================================================
// NORMALISE — Extract text + tokens from each provider's
// different response shape, tag with model metadata
// ============================================================
const nodeMeta = {
  "GPT-4o Mini":           { provider: "openai",    inCost: 0.15,   outCost: 0.60, ctx: "128K" },
  "GPT-4.1 Nano":          { provider: "openai",    inCost: 0.10,   outCost: 0.40, ctx: "1M"   },
  "Claude Haiku 3.5":      { provider: "anthropic", inCost: 0.80,   outCost: 4.00, ctx: "200K" },
  "Gemini 2.0 Flash":      { provider: "google",    inCost: 0.10,   outCost: 0.40, ctx: "1M"   },
  "Gemini 2.0 Flash Lite": { provider: "google",    inCost: 0.075,  outCost: 0.30, ctx: "1M"   },
  "Llama 3.3 70B":         { provider: "groq",      inCost: 0.59,   outCost: 0.79, ctx: "128K" },
  "Llama 3.1 8B":          { provider: "groq",      inCost: 0.05,   outCost: 0.08, ctx: "128K" },
  "Llama 4 Scout":         { provider: "groq",      inCost: 0.11,   outCost: 0.34, ctx: "131K" },
  "Qwen3 8B":              { provider: "groq",      inCost: 0.00,   outCost: 0.00, ctx: "128K" },
  "Gemma 2 9B":            { provider: "groq",      inCost: 0.20,   outCost: 0.20, ctx: "8K"   },
  "Cohere Command R7B":    { provider: "cohere",    inCost: 0.0375, outCost: 0.15, ctx: "128K" },
  "DeepSeek":              { provider: "deepseek",  inCost: 0.07,   outCost: 0.28, ctx: "64K"  }
};

// ⚠️ THIS MUST MATCH YOUR MERGE NODE CONNECTIONS TOP-TO-BOTTOM
// Remove any models you deleted from the workflow!
const modelOrder = [
  "GPT-4o Mini",
  "GPT-4.1 Nano",
  "Claude Haiku 3.5",
  "Gemini 2.0 Flash",
  "Gemini 2.0 Flash Lite",
  "Llama 3.3 70B",
  "Llama 3.1 8B",
  "Llama 4 Scout",
  "Cohere Command R7B",
  "DeepSeek"
];

const items = $input.all();
const prompt = $('Set Prompt').first().json.prompt;
const startedAt = $('Set Prompt').first().json.startedAt;

const normalised = items.map((item, index) => {
  const raw = item.json;

  // Grab the name based on the wire connection order, ignoring n8n's stripped metadata
  const nodeName = modelOrder[index] || "Unknown";

  // Try every known response shape
  let text      = "";
  let inputTok  = 0;
  let outputTok = 0;
  let success   = true;
  let errorMsg  = null;

  try {
    if (raw.choices) {
      // OpenAI / Groq / Mistral / OpenRouter shape
      text      = raw.choices[0]?.message?.content || "";
      inputTok  = raw.usage?.prompt_tokens     || 0;
      outputTok = raw.usage?.completion_tokens || 0;
    } else if (raw.content && Array.isArray(raw.content)) {
      // Anthropic shape
      text      = raw.content[0]?.text || "";
      inputTok  = raw.usage?.input_tokens  || 0;
      outputTok = raw.usage?.output_tokens || 0;
    } else if (raw.candidates) {
      // Google AI shape
      text      = raw.candidates[0]?.content?.parts[0]?.text || "";
      inputTok  = raw.usageMetadata?.promptTokenCount     || 0;
      outputTok = raw.usageMetadata?.candidatesTokenCount || 0;
    } else if (raw.message?.content) {
      // Cohere v2 shape
      text      = raw.message.content[0]?.text || "";
      inputTok  = raw.meta?.billed_units?.input_tokens  || 0;
      outputTok = raw.meta?.billed_units?.output_tokens || 0;
    } else if (raw.error || raw.message) {
      success  = false;
      errorMsg = raw.error?.message || raw.message || "Unknown error";
      text     = "ERROR: " + errorMsg;
    } else {
      success = false;
      errorMsg = "Invalid Format / Disabled Node Skipped";
      text = JSON.stringify(raw).slice(0, 200);
    }
  } catch(e) {
    success  = false;
    errorMsg = e.message;
    text     = "PARSE ERROR: " + e.message;
  }

  const meta    = nodeMeta[nodeName] || { provider: "unknown", inCost: 0, outCost: 0, ctx: "?" };
  const costUSD = ((inputTok / 1e6) * meta.inCost) + ((outputTok / 1e6) * meta.outCost);
  // Fallback to Date.now() just in case a node failed and didn't stamp the time
  const endTime = raw.endedAt || Date.now(); 
  const latency = endTime - startedAt;

  return {
    json: {
      modelName:    nodeName,
      provider:     meta.provider,
      responseText: text,
      inputTokens:  inputTok,
      outputTokens: outputTok,
      totalTokens:  inputTok + outputTok,
      costUSD,
      inCostPer1M:  meta.inCost,
      outCostPer1M: meta.outCost,
      contextWindow: meta.ctx,
      success,
      errorMsg,
      prompt,
      latencyMs: latency
    }
  };
});

return normalised;

