// Grab the output from the judge
const judgeItems = $input.all();

// Reach back and grab the original intact data from the Normalise node
const originalItems = $('Normalise All Responses').all();

return judgeItems.map((item, index) => {
  const raw = item.json;
  const originalData = originalItems[index].json; // Match the original data!

  let score  = 0;
  let reason = "Could not evaluate";

  try {
    // Extract the judge's evaluation
    const text   = raw.choices[0]?.message?.content || "";
    const clean  = text.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(clean);
    score  = parsed.score  || 0;
    reason = parsed.reason || reason;
  } catch(e) {
    reason = "Parse error: " + e.message;
  }

  // Combine the original data with the new scores
  return {
    json: {
      ...originalData, 
      qualityScore:  score,
      qualityReason: reason
    }
  };
});

// ============================================================
// BUILD FINAL RANKED REPORT
// ============================================================
const results = $input.all().map(i => i.json);

// Sort: quality desc, then latency asc
results.sort((a,b) => b.qualityScore - a.qualityScore);

const ok = results.filter(r => r.success);

const best    = arr => arr.length ? arr.reduce((a,b) => a.qualityScore > b.qualityScore ? a : b) : null;
const fastest = arr => arr.length ? arr.reduce((a,b) => a.latencyMs    < b.latencyMs    ? a : b) : null;
const cheap   = arr => arr.length ? arr.reduce((a,b) => a.costUSD      < b.costUSD      ? a : b) : null;
const value   = arr => arr.length
  ? arr.reduce((a,b) =>
      (a.qualityScore/(a.costUSD+1e-9)) > (b.qualityScore/(b.costUSD+1e-9)) ? a : b)
  : null;

const W = { quality: best(ok), cheapest: cheap(ok), value: value(ok), fastest: fastest(ok) };

// Markdown
let md = `# 🤖 AI Model Comparison — 13 Models\n`;
md += `**Prompt:** "${results[0]?.prompt}"\n`;
md += `**Run:** ${new Date().toISOString()}\n\n`;
md += `---\n\n## 🏆 Winners\n`;
if (W.quality)  md += `- 🥇 **Best Quality:** ${W.quality.modelName} — ${W.quality.qualityScore}/10\n`;
if (W.cheapest) md += `- 💰 **Cheapest:** ${W.cheapest.modelName} — $${W.cheapest.costUSD.toFixed(8)}/run\n`;
if (W.value)    md += `- ⚖️ **Best Value:** ${W.value.modelName}\n`;
if (W.fastest)  md += `- ⚡ **Fastest:** ${W.fastest.modelName} — ${W.fastest.latencyMs}ms\n`;
md += `\n---\n\n## 📊 Full Ranked Table\n\n`;
md += `| # | Model | Provider | Score | Cost/Run | In $/1M | Out $/1M | Tokens | Context | Status |\n`;
md += `|---|-------|----------|-------|----------|---------|----------|--------|---------|--------|\n`;

results.forEach((r, i) => {
  md += `| ${i+1} | **${r.modelName}** | ${r.provider} | ${r.qualityScore}/10 | $${(r.costUSD||0).toFixed(8)} | $${r.inCostPer1M} | $${r.outCostPer1M} | ${r.totalTokens||0} | ${r.contextWindow} | ${r.success ? '✅' : '❌'} |\n`;
});

md += `\n---\n\n## 📝 Responses\n\n`;
results.forEach((r,i) => {
  md += `### ${i+1}. ${r.modelName}  —  ${r.qualityScore}/10\n`;
  md += `> ${(r.responseText||'').slice(0,500)}${(r.responseText||'').length>500?'...':''}\n\n`;
  md += `*Judge: ${r.qualityReason}*\n\n---\n\n`;
});

return [{
  json: {
    summary: {
      totalModels:   results.length,
      successCount:  ok.length,
      bestQuality:   W.quality?.modelName,
      cheapest:      W.cheapest?.modelName,
      bestValue:     W.value?.modelName,
      fastest: W.fastest?.modelName
    },
    rankings:       results.map((r,i) => ({ rank: i+1, model: r.modelName, score: r.qualityScore, reason: r.qualityReason, costUSD: r.costUSD, totalTokens: r.totalTokens, context: r.contextWindow, status: r.success })),
    markdownReport: md
  }
}];

// Stamp the exact time this specific model finished
return {
  json: {
    ...$input.item.json,
    endedAt: Date.now()
  }
};

